    navigate = useNavigate();
    render() {
        return (
            <div>
                <form>
                    <input placeholder="Логин"/>
                    <input placeholder="Пароль"/>
                    <button onclick={this.myFunction}>Click here</button>
                </form>
            </div>
        )
    }
}

export default SignUp
